<template><div class="flex min-h-screen items-center justify-center bg-slate-100"><form class="w-full max-w-md rounded bg-white p-8 shadow" @submit.prevent="loginUser"><h1 class="text-center text-2xl font-black">YCKF Login</h1><input v-model="email" class="field mt-6" type="email" placeholder="admin@yckf.test"><input v-model="password" class="field" type="password" placeholder="Admin#1234"><button class="w-full rounded bg-emerald-700 py-3 font-bold text-white">Login</button><p v-if="error" class="mt-4 text-center text-red-600">{{ error }}</p></form></div></template>
<script setup lang="ts">import { ref } from 'vue';import { useRouter } from 'vue-router';const email=ref('');const password=ref('');const error=ref('');const router=useRouter();async function loginUser(){try{const res=await fetch('http://localhost:4000/api/auth/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:email.value,password:password.value})});const data=await res.json();if(!res.ok){error.value=data.message||'Invalid login';return}localStorage.setItem('yckf_token',data.token);localStorage.setItem('yckf_user',JSON.stringify(data.user));if(data.user?.role==='student')router.push('/student-dashboard');else if(data.user?.role==='secondary_admin')router.push('/admin/courses');else router.push('/admin');}catch{error.value='Network error. Try again.'}}</script><style scoped>.field{margin-bottom:1rem;width:100%;border:1px solid #cbd5e1;border-radius:.375rem;padding:.85rem}</style>
